local GameGroups = {}
local GroupHash = 0
local IsAutoStart = false ---是否满人自动开始
local StartCount = 4 ---默认开始的人数
local GameType ---默认跳转的游戏
local IsSyncClient = false

local function generateGroupId()
    GroupHash = GroupHash + 1
    return tostring(GroupHash)
end

---获取游戏组的最优区ID，用于请求dispatch地址分配游戏
---原则是：取组内所有区中玩家最多的区作为请求区
local function getGroupRegionId(group)
    local records = {}
    local function getRegionRecord(regionId)
        for _, record in pairs(records) do
            if record.regionId == regionId then
                return record
            end
        end
    end
    local manager = GameServer:getRoomManager()
    for _, userId in pairs(group) do
        if manager:isUserAttrExisted(userId) then
            local attr = manager:getUserAttrInfo(userId)
            if attr.regionId ~= 0 then
                local record = getRegionRecord(attr.regionId)
                if not record then
                    record = { regionId = attr.regionId, times = 0 }
                    table.insert(records, record)
                end
                record.times = record.times + 1
            end
        end
    end
    LogUtil.log("[GroupRegionInfo]:" .. json.encode(records), LogUtil.LogLevel.Info)
    local function getMaxTimesRegion()
        local max = { regionId = 1001, times = 0 }
        for _, record in pairs(records) do
            if record.times > max.times then
                max = record
            end
        end
        return max.regionId
    end
    local regionId = getMaxTimesRegion()
    LogUtil.log("[MaxTimesRegion]:" .. regionId, LogUtil.LogLevel.Info)
    return regionId
end

local function buildUserInfo(userId)
    local player = PlayerManager:getPlayerByUserId(userId)
    if not player then
        return
    end
    local appVersion = "1"
    local cache = GameAnalyticsCache:getClientInfo(userId)
    if cache then
        appVersion = cache.version_code
    end
    local info = {
        uid = tonumber(userId),
        name = player.name,
        pioneer = true,
        picUrl = "",
        country = "US",
        lang = "en",
        appVersion = tostring(appVersion)
    }
    local manager = GameServer:getRoomManager()
    if manager:isUserAttrExisted(userId) then
        local attr = manager:getUserAttrInfo(userId)
        info.picUrl = attr.picUrl
        info.lang = attr.lang
        info.country = attr.country
    end
    return info
end

local function testGroupStart(group, gameType)
    for _, userId in pairs(group) do
        local player = PlayerManager:getPlayerByUserId(userId)
        if player then
            local dispatchInfo = {
                ip = "127.0.0.1",
                port = 19130,
                mapId = gameType,
                mapUrl = "http://static.sandboxol.cn/mini-game-map/map-debug.zip",
                requestId = "1",
                gameType = gameType
            }
            PacketSender:sendDispatchInfo(player.rakssid, dispatchInfo)
        end
    end
end

local function takeGroupStart(groupId, gameType, mapId, callback)
    local group = GameGroups[groupId]
    if not group then
        return
    end
    if Platform.isWindow() then
        testGroupStart(group, gameType)
        return
    end
    local regionId = getGroupRegionId(group)
    WebService:GetDispatchUrl(regionId, function(info)
        if not info then
            LogUtil.log("[GameGroupStart] get dispatch url failed.", LogUtil.LogLevel.Error)
            if callback then
                callback(false, group)
            end
            return
        end
        local data = {
            gtype = gameType,
            rid = info.region,
            ever = EngineVersionSetting.getEngineVersion(),
            prv = false,
            mem = {},
            mapid = mapId
        }
        for _, userId in pairs(group) do
            local member = buildUserInfo(userId)
            if member then
                table.insert(data.mem, member)
            end
        end
        LogUtil.log("[GameGroupStart][Data]:" .. json.encode(data), LogUtil.LogLevel.Info)
        WebService:GetDispatchParty(info.dispUrl, data, function(data, code)
            if code ~= 1 then
                LogUtil.log("[GameGroupStart] get dispatch party failed. [code]:" .. code, LogUtil.LogLevel.Error)
                if callback then
                    callback(false, group)
                end
                return
            end
            ---分发ip和port给玩家，作为跳转服务器的数据
            local ip = StringUtil.split(data.gaddr, ":")[1]
            local port = StringUtil.split(data.gaddr, ":")[2]
            for _, userId in pairs(group) do
                local player = PlayerManager:getPlayerByUserId(userId)
                if player then
                    local dispatchInfo = {
                        ip = ip,
                        port = port,
                        mapId = data.mid,
                        mapUrl = data.downurl,
                        requestId = data.requestIds[userId],
                        gameType = gameType
                    }
                    PacketSender:sendDispatchInfo(player.rakssid, dispatchInfo)
                end
            end
            if callback then
                callback(true, group)
            end
        end)
    end)
    GameGroups[groupId] = nil
end

---通过userId获取游戏组ID
local function getUserGroupId(userId)
    if not userId then
        return nil
    end
    for groupId, group in pairs(GameGroups) do
        for _, memberId in pairs(group) do
            if memberId == tostring(userId) then
                return groupId
            end
        end
    end
    return nil
end

---通过userId查找游戏组或生成游戏组
local function getGroup(userId)
    local groupId = getUserGroupId(userId)
    if not groupId then
        groupId = generateGroupId()
    end
    local group = GameGroups[groupId]
    if not group then
        group = {}
    end
    GameGroups[groupId] = group
    return group
end

GameGroupManager = {}

function GameGroupManager:setAutoStart(autoStart, startCount, gameType)
    IsAutoStart = autoStart
    StartCount = startCount
    GameType = gameType
end

function GameGroupManager:setSyncClient(syncClient)
    IsSyncClient = syncClient
end

function GameGroupManager:takeGroupStart(userId, gameType, mapId, callback)
    local groupId = getUserGroupId(userId)
    if not groupId then
        return
    end
    gameType = gameType or GameType
    mapId = mapId or ""
    takeGroupStart(groupId, gameType, mapId, callback)
end

function GameGroupManager:addUser(userId, targetId, callback)
    local player = PlayerManager:getPlayerByUserId(userId)
    if not player then
        return
    end
    local group = getGroup(targetId)
    table.insert(group, tostring(userId))
    if not IsAutoStart then
        return
    end
    if #group == StartCount then
        self:takeGroupStart(userId, callback)
    end
end

function GameGroupManager:addUsers(userIds, targetId, callback)
    local group = getGroup(targetId)
    for _, userId in pairs(userIds) do
        local player = PlayerManager:getPlayerByUserId(userId)
        if player then
            table.insert(group, tostring(userId))
        end
    end
    if not IsAutoStart then
        return
    end
    if #group == StartCount then
        self:takeGroupStart(userIds[1], callback)
    end
end

function GameGroupManager:removeUser(userId)
    local groupId = getUserGroupId(userId)
    if not groupId then
        return
    end
    local group = GameGroups[groupId]
    for pos, memberId in pairs(group) do
        if memberId == tostring(userId) then
            table.remove(group, pos)
            break
        end
    end
end

function GameGroupManager:getGroupUserCount(userId)
    local groupId = getUserGroupId(userId)
    if not groupId then
        return 0
    end
    local group = GameGroups[groupId]
    return #group
end